solution_code:
#include <iostream>

template <typename T>
class Classifier {
public:
    static const char* kind() { return "value"; }
};

template <typename T>
class Classifier<T*> {
public:
    static const char* kind() { return "pointer"; }
};

int main() {
    std::cout << Classifier<int>::kind()     << "\n";
    std::cout << Classifier<int*>::kind()    << "\n";
    std::cout << Classifier<double*>::kind() << "\n";
    return 0;
}

