#include <iostream>

template <typename T>
class Wrapper {
    T val_;
public:
    explicit Wrapper(T v) : val_{v} {}
    void show() const { std::cout << "val: " << val_ << "\n"; }
};

template <typename T>
class Wrapper<T*> {
    T* ptr_;
public:
    explicit Wrapper(T* p) : ptr_{p} {}
    void show() const { std::cout << "ptr: " << ptr_ << "\n"; }  // BUG: prints address, not value
};

int main() {
    int x = 7;
    Wrapper<int> a{x};
    Wrapper<int*> b{&x};
    a.show();
    b.show();
    return 0;
}

solution_code:
#include <iostream>

template <typename T>
class Wrapper {
    T val_;
public:
    explicit Wrapper(T v) : val_{v} {}
    void show() const { std::cout << "val: " << val_ << "\n"; }
};

template <typename T>
class Wrapper<T*> {
    T* ptr_;
public:
    explicit Wrapper(T* p) : ptr_{p} {}
    void show() const { std::cout << "ptr: " << *ptr_ << "\n"; }
};

int main() {
    int x = 7;
    Wrapper<int> a{x};
    Wrapper<int*> b{&x};
    a.show();
    b.show();
    return 0;
}
